sql:
SELECT issue_category, COUNT(*) AS issue_count
FROM political_issues
GROUP BY issue_category;

SELECT AVG(2023 - CAST(SUBSTR(date_of_birth, 1, 4) AS INTEGER)) AS average_age
FROM representatives
WHERE country = 'Sweden';

external_knowledge:
- Top-performing representatives are determined by their party's total votes in recent elections; 
- Recent elections refer to those held after January 1, 2022; 
- Social media presence includes the platform and handle of the representative.

sql:
SELECT full_name
FROM representatives
WHERE date_of_birth = (SELECT MIN(date_of_birth) FROM representatives);

SELECT COUNT(*) AS active_reps_count
FROM party_affiliations
WHERE current_status = 'Active';

SELECT COUNT(*) AS total_swedish_representatives
FROM representatives
WHERE country = 'Sweden';
